import{_ as e,o as a,c as t,Q as i}from"./chunks/framework.b67c47e6.js";const p=JSON.parse('{"title":"Quantities / BoM Matrix","description":"","frontmatter":{},"headers":[],"relativePath":"guide/quantities/index.md","filePath":"guide/quantities/index.md","lastUpdated":1773939149000}'),s={name:"guide/quantities/index.md"},n=i('<h1 id="quantities-bom-matrix" tabindex="-1">Quantities / BoM Matrix <a class="header-anchor" href="#quantities-bom-matrix" aria-label="Permalink to &quot;Quantities / BoM Matrix&quot;">​</a></h1><p>The Quantities view lets you plan how many of each design to produce across project phases and batches. It uses a matrix layout where you define quantities before generating the actual constructibles.</p><nav class="table-of-contents"><ul><li><a href="#matrix-layout">Matrix Layout</a></li><li><a href="#view-modes">View Modes</a><ul><li><a href="#phase-view">Phase View</a></li><li><a href="#batch-view">Batch View</a></li></ul></li><li><a href="#managing-quantities">Managing Quantities</a></li><li><a href="#generating-constructibles">Generating Constructibles</a></li><li><a href="#area-metrics">Area Metrics</a></li></ul></nav><h2 id="matrix-layout" tabindex="-1">Matrix Layout <a class="header-anchor" href="#matrix-layout" aria-label="Permalink to &quot;Matrix Layout&quot;">​</a></h2><p>The matrix is organized as:</p><ul><li><strong>Rows</strong> — Design names (assemblies and modules). Only the latest revision of each design is shown.</li><li><strong>Columns</strong> — Project phases (or batches, depending on the view).</li><li><strong>Cells</strong> — The quantity count for each design × phase combination.</li><li><strong>Totals</strong> — Row totals (all phases for a design) and column totals (all designs in a phase).</li></ul><h2 id="view-modes" tabindex="-1">View Modes <a class="header-anchor" href="#view-modes" aria-label="Permalink to &quot;View Modes&quot;">​</a></h2><h3 id="phase-view" tabindex="-1">Phase View <a class="header-anchor" href="#phase-view" aria-label="Permalink to &quot;Phase View&quot;">​</a></h3><p>Shows a high-level summary with one column per project phase. Each cell shows the total quantity of a design across all batches in that phase.</p><h3 id="batch-view" tabindex="-1">Batch View <a class="header-anchor" href="#batch-view" aria-label="Permalink to &quot;Batch View&quot;">​</a></h3><p>Select a specific phase to drill down into its batches. Each column represents a batch, showing the detailed quantity breakdown.</p><h2 id="managing-quantities" tabindex="-1">Managing Quantities <a class="header-anchor" href="#managing-quantities" aria-label="Permalink to &quot;Managing Quantities&quot;">​</a></h2><ul><li><strong>Edit cells</strong> — Click on a quantity cell to change the count.</li><li><strong>Add phase</strong> — Create a new project phase.</li><li><strong>Add batch</strong> — Create a new batch within a phase.</li><li><strong>Delete phase/batch</strong> — Remove from the project.</li><li><strong>Save</strong> — Persist the quantity matrix.</li><li><strong>Load from project</strong> — Restore previously saved quantities.</li></ul><h2 id="generating-constructibles" tabindex="-1">Generating Constructibles <a class="header-anchor" href="#generating-constructibles" aria-label="Permalink to &quot;Generating Constructibles&quot;">​</a></h2><p>Once your quantities are defined, click <strong>Generate Constructibles</strong> to create the actual assembly and module instances based on the matrix counts.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Before generating, validate that your phase counts match your batch counts. The system will warn you if there are discrepancies.</p></div><h2 id="area-metrics" tabindex="-1">Area Metrics <a class="header-anchor" href="#area-metrics" aria-label="Permalink to &quot;Area Metrics&quot;">​</a></h2><p>Toggle the area display to see total square meters alongside quantity counts. This helps estimate material requirements and production workload.</p>',18),o=[n];function r(l,h,c,u,d,g){return a(),t("div",null,o)}const b=e(s,[["render",r]]);export{p as __pageData,b as default};
